int main() {
    int grid[81];
    int pos;
    int val;
    int ok;
    int found;
    int row;
    int col;
    int rs;
    int bs;
    int idx;
    int g;
    int done;
    int i;
    int br;
    int bc;
    int br2;
    int bc2;
    int temp;

    grid[0] = -5; grid[1] = -3; grid[2] = 0; grid[3] = 0; grid[4] = -7; grid[5] = 0; grid[6] = 0; grid[7] = 0; grid[8] = 0;
    grid[9] = -6; grid[10] = 0; grid[11] = 0; grid[12] = -1; grid[13] = -9; grid[14] = -5; grid[15] = 0; grid[16] = 0; grid[17] = 0;
    grid[18] = 0; grid[19] = -9; grid[20] = -8; grid[21] = 0; grid[22] = 0; grid[23] = 0; grid[24] = 0; grid[25] = -6; grid[26] = 0;
    grid[27] = -8; grid[28] = 0; grid[29] = 0; grid[30] = 0; grid[31] = -6; grid[32] = 0; grid[33] = 0; grid[34] = 0; grid[35] = -3;
    grid[36] = -4; grid[37] = 0; grid[38] = 0; grid[39] = -8; grid[40] = 0; grid[41] = -3; grid[42] = 0; grid[43] = 0; grid[44] = -1;
    grid[45] = -7; grid[46] = 0; grid[47] = 0; grid[48] = 0; grid[49] = -2; grid[50] = 0; grid[51] = 0; grid[52] = 0; grid[53] = -6;
    grid[54] = 0; grid[55] = -6; grid[56] = 0; grid[57] = 0; grid[58] = 0; grid[59] = 0; grid[60] = -2; grid[61] = -8; grid[62] = 0;
    grid[63] = 0; grid[64] = 0; grid[65] = 0; grid[66] = -4; grid[67] = -1; grid[68] = -9; grid[69] = 0; grid[70] = 0; grid[71] = -5;
    grid[72] = 0; grid[73] = 0; grid[74] = 0; grid[75] = 0; grid[76] = -8; grid[77] = 0; grid[78] = 0; grid[79] = -7; grid[80] = -9;

    pos = 0;
    found = 0;
    while (pos < 81 && found == 0) {
        if (grid[pos] == 0) {
            found = 1;
        } else {
            pos = pos + 1;
        }
    }

    done = 0;
    while (done == 0) {
        if (pos > 80) {
            done = 1;
        } else if (pos < 0) {
            done = 2;
        } else {
            val = grid[pos] + 1;
            found = 0;

            while (val < 10 && found == 0) {
                ok = 1;

                row = 0;
                temp = pos;
                while (temp >= 9) {
                    temp = temp - 9;
                    row = row + 1;
                }
                col = temp;

                rs = (row << 3) + row;
                idx = rs;
                i = 0;
                while (i < 9) {
                    if (idx != pos) {
                        g = grid[idx];
                        if (g < 0) { g = -g; }
                        if (g == val) { ok = 0; }
                    }
                    idx = idx + 1;
                    i = i + 1;
                }

                if (ok != 0) {
                    idx = col;
                    i = 0;
                    while (i < 9) {
                        if (idx != pos) {
                            g = grid[idx];
                            if (g < 0) { g = -g; }
                            if (g == val) { ok = 0; }
                        }
                        idx = idx + 9;
                        i = i + 1;
                    }
                }

                if (ok != 0) {
                    br = row;
                    temp = br;
                    while (temp >= 3) { temp = temp - 3; }
                    br = br - temp;
                    bc = col;
                    temp = bc;
                    while (temp >= 3) { temp = temp - 3; }
                    bc = bc - temp;
                    bs = (br << 3) + br + bc;

                    idx = bs;
                    br2 = 0;
                    while (br2 < 3) {
                        bc2 = 0;
                        while (bc2 < 3) {
                            if (idx != pos) {
                                g = grid[idx];
                                if (g < 0) { g = -g; }
                                if (g == val) { ok = 0; }
                            }
                            idx = idx + 1;
                            bc2 = bc2 + 1;
                        }
                        idx = idx + 6;
                        br2 = br2 + 1;
                    }
                }

                if (ok != 0) {
                    found = 1;
                } else {
                    val = val + 1;
                }
            }

            if (found != 0) {
                grid[pos] = val;
                pos = pos + 1;
                found = 0;
                while (pos < 81 && found == 0) {
                    if (grid[pos] < 0) {
                        pos = pos + 1;
                    } else {
                        found = 1;
                    }
                }
            } else {
                grid[pos] = 0;
                pos = pos - 1;
                found = 0;
                while (pos >= 0 && found == 0) {
                    if (grid[pos] < 0) {
                        pos = pos - 1;
                    } else {
                        found = 1;
                    }
                }
            }
        }
    }

    return done;
}
